/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
[ExtensionOf(formDataSourcestr(LogisticsPostalAddress,LogisticsLocation))]
internal final class ETGLogisticsPostalAddressFormDSDMS_Extension
{
}

Method.Source:
public int active()
{
    int ret = next active();

    FormRun formRun = this.formRun();

    // Example: check if opened from CustTable form and flag is set to disable edits
    Args args = formRun.args();
    if (args && args.caller() && args.caller().name() == formStr(LogisticsPostalAddressGrid))
    {
        ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);
    }
    return ret;
}
